import { useParams } from "react-router-dom";
import { useState, useEffect } from "react";
import axios from "axios";

const EditUser = () => {
    const { userID } = useParams(); // Get user ID from URL
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [editedUser, setEditedUser] = useState({
        s_name: '',
        s_email: '',
        i_userlevel: '',
        s_regno: '',
        b_active: true,
    });

    useEffect(() => {
        axios.get(`http://localhost:5000/api/user/${userID}`)
            .then(response => {
              //  console.log("Fetched users:", response.data); // Debugging
                setUser(response.data);
                setLoading(false);
            })
            .catch(error => {
                console.error("Error fetching user data:", error);
                setError("Failed to load user data.");
                setLoading(false);
            });
    }, [userID]);

    if (loading) return <p>Loading user data...</p>;
    if (error) return <p>{error}</p>;

    return (
        <div className="table-container">
            <h2>Endre bruker</h2>
            <form onSubmit={handleSubmit}>
                <table>
                    <tbody>
                        <tr>
                            <td><strong>Navn:</strong></td>
                            <td>
                                <input
                                    type="text"
                                    name="s_name"
                                    value={editedUser.s_name}
                                    onChange={handleChange}
                                />
                            </td>
                        </tr>
                        <tr>
                            <td><strong>Epost:</strong></td>
                            <td>
                                <input
                                    type="email"
                                    name="s_email"
                                    value={editedUser.s_email}
                                    onChange={handleChange}
                                />
                            </td>
                        </tr>
                        <tr>
                            <td><strong>Brukertype:</strong></td>
                            <td>
                                <select
                                    name="i_userlevel"
                                    value={editedUser.i_userlevel}
                                    onChange={handleChange}
                                >
                                    <option value="1">Admin</option>
                                    <option value="2">User</option>
                                    <option value="3">Guest</option>
                                </select>
                            </td>
                        </tr>
                        <tr>
                            <td><strong>Reg. nummer:</strong></td>
                            <td>
                                <input
                                    type="text"
                                    name="s_regno"
                                    value={editedUser.s_regno}
                                    onChange={handleChange}
                                />
                            </td>
                        </tr>
                        <tr>
                            <td><strong>Aktiv:</strong></td>
                            <td>
                                <input
                                    type="checkbox"
                                    name="b_active"
                                    checked={editedUser.b_active}
                                    onChange={(e) => setEditedUser(prevState => ({
                                        ...prevState,
                                        b_active: e.target.checked,
                                    }))}
                                />
                            </td>
                        </tr>
                    </tbody>
                </table>
                <button type="submit" className="btn btn-blue">Save</button>
            </form>
        </div>
    );
};


export default EditUser;
